import{_ as i,o as e,c as a,a0 as t}from"./chunks/framework.Cl79jK2u.js";const c=JSON.parse('{"title":"CLI Reference","description":"","frontmatter":{},"headers":[],"relativePath":"reference/cli.md","filePath":"reference/cli.md"}'),h={name:"reference/cli.md"};function n(d,s,l,r,p,o){return e(),a("div",null,[...s[0]||(s[0]=[t('<h1 id="cli-reference" tabindex="-1">CLI Reference <a class="header-anchor" href="#cli-reference" aria-label="Permalink to &quot;CLI Reference&quot;">​</a></h1><h2 id="commands" tabindex="-1">Commands <a class="header-anchor" href="#commands" aria-label="Permalink to &quot;Commands&quot;">​</a></h2><h3 id="moxie-init" tabindex="-1"><code>moxie init</code> <a class="header-anchor" href="#moxie-init" aria-label="Permalink to &quot;`moxie init`&quot;">​</a></h3><p>Interactive setup for Telegram. Prompts for bot token, chat ID, and a default workspace, writes <code>~/.config/moxie/config.json</code>, and can optionally install/start the background service. This is the recommended first-run path.</p><h3 id="moxie-serve" tabindex="-1"><code>moxie serve</code> <a class="header-anchor" href="#moxie-serve" aria-label="Permalink to &quot;`moxie serve`&quot;">​</a></h3><p>Start the chat agent service. Runs all configured transports and dispatches messages to agent backends.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [--cwd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">di</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">r</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">]</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [--transport </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">telegram</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">slack</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">]</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Flag</th><th>Description</th></tr></thead><tbody><tr><td><code>--cwd</code></td><td>Explicit working directory override. Without this flag, <code>moxie serve</code> prefers the current shell directory, then <code>default_cwd</code>, then the platform workspace default.</td></tr><tr><td><code>--transport</code></td><td>Run only the specified transport</td></tr></tbody></table><h3 id="moxie-send" tabindex="-1"><code>moxie send</code> <a class="header-anchor" href="#moxie-send" aria-label="Permalink to &quot;`moxie send`&quot;">​</a></h3><p>Send a message directly to the configured transport. If both transports are configured, use <code>--transport telegram</code> or <code>--transport slack</code>.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> send</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [--transport </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">telegram</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">slack</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">]</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">messag</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><h3 id="moxie-messages" tabindex="-1"><code>moxie messages</code> <a class="header-anchor" href="#moxie-messages" aria-label="Permalink to &quot;`moxie messages`&quot;">​</a></h3><p>List recent messages. <code>moxie msg</code> is an alias.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> messages</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [--json</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">--raw]</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [-n </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">N]</span></span></code></pre></div><h3 id="moxie-schedule" tabindex="-1"><code>moxie schedule</code> <a class="header-anchor" href="#moxie-schedule" aria-label="Permalink to &quot;`moxie schedule`&quot;">​</a></h3><p>Manage scheduled messages and dispatches.</p><p>Supported schedules are materialized automatically into native backends on macOS (<code>launchd</code>) and Windows (Task Scheduler) when possible. Unsupported shapes fall back to Moxie&#39;s in-process scheduler. Linux currently uses the in-process scheduler only.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> schedule</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [flags]      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Create a schedule</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> schedule</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">             # List all schedules</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> schedule</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> show</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # Show schedule details</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> schedule</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rm</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # Delete a schedule</span></span></code></pre></div><p>Use <code>--conversation &lt;provider:channel[:thread]&gt;</code> to target a specific conversation directly, or <code>--transport &lt;telegram|slack&gt;</code> to use that transport&#39;s configured default conversation. If only one transport is configured, <code>--transport</code> can be omitted.</p><h4 id="schedule-add-flags" tabindex="-1"><code>schedule add</code> flags <a class="header-anchor" href="#schedule-add-flags" aria-label="Permalink to &quot;`schedule add` flags&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Flag</th><th>Description</th></tr></thead><tbody><tr><td><code>--transport</code></td><td>Use the configured default conversation for one transport</td></tr><tr><td><code>--conversation</code></td><td>Target a specific conversation ID directly</td></tr><tr><td><code>--action</code></td><td>Required: <code>send</code> or <code>dispatch</code></td></tr><tr><td><code>--in</code></td><td>Relative one-shot delay (e.g. <code>5m</code>, <code>2h</code>)</td></tr><tr><td><code>--at</code></td><td>Exact one-shot time. Accepts RFC 3339, <code>YYYY-MM-DDTHH:MM</code>, or <code>YYYY-MM-DD HH:MM</code></td></tr><tr><td><code>--every</code></td><td>Recurring elapsed-time interval (e.g. <code>15m</code>, <code>2h</code>)</td></tr><tr><td><code>--cron</code></td><td>Recurring portable 5-field cron expression</td></tr><tr><td><code>--text</code></td><td>Required message or prompt text</td></tr><tr><td><code>--backend</code></td><td>Override backend for <code>dispatch</code> schedules</td></tr><tr><td><code>--model</code></td><td>Override model for <code>dispatch</code> schedules</td></tr><tr><td><code>--thread</code></td><td>Override thread for <code>dispatch</code> schedules</td></tr><tr><td><code>--cwd</code></td><td>Override working directory for <code>dispatch</code> schedules</td></tr></tbody></table><p>Use exactly one of <code>--in</code>, <code>--at</code>, <code>--every</code>, or <code>--cron</code>.</p><p>For <code>dispatch</code> schedules, Moxie captures the current backend, model, thread, and working directory at creation time unless you override them explicitly. <code>send</code> schedules ignore those dispatch-specific overrides.</p><p><code>moxie schedule show &lt;id&gt;</code> includes sync metadata such as <code>Managed by</code>, <code>Sync state</code>, and <code>Sync error</code> when applicable, which is how you can see whether a schedule is running natively or via the in-process fallback.</p><h3 id="moxie-subagent" tabindex="-1"><code>moxie subagent</code> <a class="header-anchor" href="#moxie-subagent" aria-label="Permalink to &quot;`moxie subagent`&quot;">​</a></h3><p>Delegate work to a background agent.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> subagent</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --backend</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --text</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">tas</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">k</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [flags]</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> subagent</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [--all]     </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># List active subagent jobs</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> subagent</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> show</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">job-i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # Show full details for a job</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> subagent</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cancel</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">job-i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # Cancel a running job</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Flag</th><th>Description</th></tr></thead><tbody><tr><td><code>--backend</code></td><td>Required. Target backend</td></tr><tr><td><code>--text</code></td><td>Required. Task prompt</td></tr><tr><td><code>--context-budget</code></td><td>Context budget for compiled parent context</td></tr><tr><td><code>--model</code></td><td>Model override</td></tr><tr><td><code>--cwd</code></td><td>Working directory override</td></tr><tr><td><code>--parent-job</code></td><td>Explicit parent dispatch job to attach to</td></tr></tbody></table><p><code>moxie subagent list</code> shows active subagent jobs by default. Use <code>--all</code> to include completed and canceled jobs. <code>moxie subagent show</code> displays full job details including status, backend, model, thread, depth, attempt, run ID, and timestamps.</p><h3 id="moxie-result" tabindex="-1"><code>moxie result</code> <a class="header-anchor" href="#moxie-result" aria-label="Permalink to &quot;`moxie result`&quot;">​</a></h3><p>Retrieve subagent results.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> result</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [--limit </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">]</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # List completed results</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> result</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> show</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # Show a specific result artifact</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> result</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> search</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">quer</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">y</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # Search result artifacts by task text</span></span></code></pre></div><h3 id="moxie-threads" tabindex="-1"><code>moxie threads</code> <a class="header-anchor" href="#moxie-threads" aria-label="Permalink to &quot;`moxie threads`&quot;">​</a></h3><p>View thread history.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> threads</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> show</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # Show turns for a thread</span></span></code></pre></div><h3 id="moxie-service" tabindex="-1"><code>moxie service</code> <a class="header-anchor" href="#moxie-service" aria-label="Permalink to &quot;`moxie service`&quot;">​</a></h3><p>Control the background service.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [--cwd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">di</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">r</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">]</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [--transport </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">telegram</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">slack</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">]</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> uninstall</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reload</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><p><code>moxie service install</code> uses <code>--cwd</code> if provided. Otherwise it uses <code>default_cwd</code> from config, or the platform-managed workspace default.</p><p>On Linux, <code>reload</code> sends <code>SIGHUP</code> to the running service so it can reload config and backend definitions without exiting the process.</p><p>On macOS, <code>moxie service</code> manages the LaunchAgent <code>io.github.1broseidon.moxie</code> at <code>~/Library/LaunchAgents/io.github.1broseidon.moxie.plist</code>.</p><p>On Windows, <code>moxie service install</code> and the related service control commands are not implemented yet.</p><h2 id="operator-commands" tabindex="-1">Operator Commands <a class="header-anchor" href="#operator-commands" aria-label="Permalink to &quot;Operator Commands&quot;">​</a></h2><p>These commands are mainly for Telegram transport troubleshooting, scripted intake tests, and native schedule plumbing. Most users should not need them during normal use.</p><h3 id="moxie-schedule-fire" tabindex="-1"><code>moxie schedule fire</code> <a class="header-anchor" href="#moxie-schedule-fire" aria-label="Permalink to &quot;`moxie schedule fire`&quot;">​</a></h3><p>Run a schedule immediately by ID.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> schedule</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fire</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>This is primarily internal/operator plumbing used by native <code>launchd</code> and Task Scheduler entries. Normal schedule management should go through <code>moxie schedule add</code>, <code>list</code>, <code>show</code>, and <code>rm</code>.</p><h3 id="moxie-poll" tabindex="-1"><code>moxie poll</code> <a class="header-anchor" href="#moxie-poll" aria-label="Permalink to &quot;`moxie poll`&quot;">​</a></h3><p>Show only new Telegram messages since the last poll and advance the stored update cursor.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> poll</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [--json</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">--raw]</span></span></code></pre></div><h3 id="moxie-cursor" tabindex="-1"><code>moxie cursor</code> <a class="header-anchor" href="#moxie-cursor" aria-label="Permalink to &quot;`moxie cursor`&quot;">​</a></h3><p>Inspect or modify the stored Telegram update cursor.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cursor</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                    # Show current position</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cursor</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">update_i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # Set to specific position</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">moxie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cursor</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reset</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # Reset to 0</span></span></code></pre></div>',54)])])}const g=i(h,[["render",n]]);export{c as __pageData,g as default};
